import json
import matplotlib.pyplot as plt
import numpy as np
import os

def main():
    # 1. Load local results generated by run_ompar.py
    results_file = 'evaluation/ompar_results.json'
    try:
        with open(results_file, 'r') as f:
            local_data = json.load(f)
    except FileNotFoundError:
        print(f"Error: Could not find '{results_file}'. Please run 'run_ompar.py' first.")
        return

    # 2. Hardcode the paper's results (from Table 4)
    # The paper reports 71% Precision, 81% Recall, 74% Accuracy.
    # TP: 311, FP: 127, TN: 262, FN: 70.
    paper_data = {
        "Precision": 0.71,
        "Recall": 0.81,
        "Accuracy": 0.74,
        "TP": 311,
        "FP": 127,
        "TN": 262,
        "FN": 70,
        "Total": 311 + 127 + 262 + 70
    }

    # Set up styling for academic-quality plots
    plt.style.use('ggplot')
    colors = ['#2c3e50', '#e74c3c'] # Dark blue for local, Red for Paper

    # ---------------------------------------------------------
    # Plot 1: Performance Metrics Comparison (Bar Chart)
    # ---------------------------------------------------------
    labels = ['Precision', 'Recall', 'Accuracy']
    local_metrics = [local_data['Precision'] * 100, local_data['Recall'] * 100, local_data['Accuracy'] * 100]
    paper_metrics = [paper_data['Precision'] * 100, paper_data['Recall'] * 100, paper_data['Accuracy'] * 100]

    x = np.arange(len(labels))
    width = 0.35

    fig, ax = plt.subplots(figsize=(8, 6))
    rects1 = ax.bar(x - width/2, local_metrics, width, label='Dataset propio', color=colors[0])
    rects2 = ax.bar(x + width/2, paper_metrics, width, label='Paper (HeCBench 770)', color=colors[1])

    ax.set_ylabel('Porcentage (%)', fontsize=12, fontweight='bold')
    ax.set_title('Rendimiento OMPar: Evaluación propia vs. Paper', fontsize=14, fontweight='bold')
    ax.set_xticks(x)
    ax.set_xticklabels(labels, fontsize=12)
    ax.set_ylim(0, 100)
    ax.legend(loc='upper right')

    # Attach percentage labels to the top of bars
    ax.bar_label(rects1, fmt='%.1f%%', padding=3, fontsize=11)
    ax.bar_label(rects2, fmt='%.1f%%', padding=3, fontsize=11)

    fig.tight_layout()
    plt.savefig('evaluation/metrics_comparison.png', dpi=300)
    print("Saved -> evaluation/metrics_comparison.png")

    # ---------------------------------------------------------
    # Plot 2: Confusion Matrix Distribution (Grouped Horizontal Bar)
    # ---------------------------------------------------------
    # Convert to proportions since total dataset sizes differ
    local_cm_props = [
        (local_data['TP'] / local_data['Total']) * 100, 
        (local_data['FP'] / local_data['Total']) * 100, 
        (local_data['TN'] / local_data['Total']) * 100, 
        (local_data['FN'] / local_data['Total']) * 100
    ]
    
    paper_cm_props = [
        (paper_data['TP'] / paper_data['Total']) * 100, 
        (paper_data['FP'] / paper_data['Total']) * 100, 
        (paper_data['TN'] / paper_data['Total']) * 100, 
        (paper_data['FN'] / paper_data['Total']) * 100
    ]

    cm_labels = ['True Positives (TP)', 'False Positives (FP)', 'True Negatives (TN)', 'False Negatives (FN)']
    y = np.arange(len(cm_labels))

    fig2, ax2 = plt.subplots(figsize=(10, 6))
    rects_cm1 = ax2.barh(y - width/2, local_cm_props, width, label='Evaluación propia', color=colors[0])
    rects_cm2 = ax2.barh(y + width/2, paper_cm_props, width, label='Paper (HeCBench 770)', color=colors[1])

    ax2.set_xlabel('Proporción del total de loops evaluados (%)', fontsize=12, fontweight='bold')
    ax2.set_title('Comparación de la distribución de la matriz de confusión', fontsize=12, fontweight='bold')
    ax2.set_yticks(y)
    ax2.set_yticklabels(cm_labels, fontsize=12)
    ax2.set_xlim(0, max(max(local_cm_props), max(paper_cm_props)) + 10)
    ax2.legend(loc='lower right')
    
    ax2.bar_label(rects_cm1, fmt='%.1f%%', padding=3, fontsize=11)
    ax2.bar_label(rects_cm2, fmt='%.1f%%', padding=3, fontsize=11)

    fig2.tight_layout()
    plt.savefig('evaluation/confusion_matrix_comparison.png', dpi=300)
    print("Saved -> evaluation/confusion_matrix_comparison.png")

if __name__ == '__main__':
    main()